class Robohash {

    /* Public API */

    static svg(text) {
        const hash = this._hash(text);

        return this._svgTemplate(
            this.colors[hash[0] % this.colors.length],
            this.bgColors[hash[1] % this.bgColors.length],
            hash[2],
            hash[3],
            hash[4],
            hash[5],
            hash[6]
        );
    }

    static render(text, element) {
        element.innerHTML = this.svg(text);
    }

    static toDataUrl(text) {
        return `data:image/svg+xml;base64,${btoa(this.svg(text))}`;
    }

    /* Private API */

    static _svgTemplate(color, backgroundColor, bodyNr, faceNr, eyesNr, mouthNr, accessoryNr) {
        return this._$svg(
            this._$robohash(color, backgroundColor, bodyNr, faceNr, eyesNr, mouthNr, accessoryNr)
        );
    }

    static _$robohash(color, backgroundColor, bodyNr, faceNr, eyesNr, mouthNr, accessoryNr) {
        return `
            <g style="color:${color}">
                <rect fill="${backgroundColor}" x="0" y="0" width="320" height="320"></rect>
                ${this._$use('body', bodyNr)}
                ${this._$use('face', faceNr)}
                ${this._$use('eyes', eyesNr)}
                ${this._$use('mouth', mouthNr)}
                ${this._$use('accessory', accessoryNr)}
            </g>
        `;
    }

    static _$svg(content) {
        return `
            <svg viewBox="0 0 320 320" width="320" height="320"
                 xmlns="http://www.w3.org/2000/svg"
                 xmlns:xlink="http://www.w3.org/1999/xlink">
                ${content}
            </svg>
        `;
    }

    static _$use(part, index) {
        return `
            <use width="320"
                 height="300"
                 transform="translate(0,20)"
                 xlink:href="static/robohash.min.svg#${part}-${this._assetIndex(index)}" />
        `;
    }

    static get colors() {
        return [
            '#ff9800',
            '#E53935',
            '#FDD835',
            '#3f51b5',
            '#03a9f4',
            '#9c27b0',
            '#009688',
            '#EC407A',
            '#8bc34a',
            '#795548'
        ];
    }

    static get bgColors() {
        return [
            '#FF8A80',
            '#F48FB1',
            '#ea80fc',
            '#8c9eff',
            '#80d8ff',
            '#CFD8DC',
            '#1DE9B6',
            '#00C853',
            '#FF9E80',
            '#FFE57F'
        ];
    }

    static _assetIndex(index) {
        const i = (Number(index) % 20) + 1;   // ensure valid range
        return i < 10 ? '0' + i : String(i);
    }

    /* Improved deterministic hash */

    static _hash(text) {
        // Simple fast deterministic integer hash
        let hash = 0;
        for (let i = 0; i < text.length; i++) {
            hash = ((hash << 5) - hash) + text.charCodeAt(i);
            hash |= 0; // force 32-bit int
        }

        // Convert to positive number string
        const str = Math.abs(hash).toString().padStart(10, '0');

        // Return array of digits
        return str.slice(0, 10).split('').map(n => Number(n));
    }
}

window.Robohash = Robohash;